import { useState } from 'react';
import { useAuth } from '../lib/AuthContext';
import { api } from '../lib/api';

const TRUCK_BG = "data:image/jpeg;base64,";

const InterlandLogo = () => (
  <svg viewBox="0 0 360 90" xmlns="http://www.w3.org/2000/svg" style={{ width: '100%', maxWidth: 300, display: 'block', margin: '0 auto 4px' }}>
    <rect x="0" y="12" width="28" height="6" rx="1.5" fill="#00AEEF" opacity="0.9"/>
    <rect x="0" y="22" width="18" height="4" rx="1.5" fill="#00AEEF" opacity="0.6"/>
    <rect x="0" y="30" width="12" height="3" rx="1.5" fill="#00AEEF" opacity="0.35"/>
    <text x="36" y="38"
      fontFamily="Arial Black, Arial, sans-serif"
      fontWeight="900" fontSize="34" fill="#00AEEF" fontStyle="italic"
      letterSpacing="-0.5">INTERLAND</text>
    <text x="36" y="68"
      fontFamily="Arial Black, Arial, sans-serif"
      fontWeight="900" fontSize="28" fill="#00AEEF" fontStyle="italic"
      letterSpacing="0.5">DISTRIBUTION</text>
    <text x="38" y="84"
      fontFamily="Arial, sans-serif"
      fontWeight="400" fontSize="10" fill="#555"
      letterSpacing="2.5">INTEGRATED LINEHAUL SOLUTIONS</text>
  </svg>
);

export default function Login() {
  const { login } = useAuth();
  const [mode, setMode] = useState('login');
  const [form, setForm] = useState({ username: '', password: '' });
  const [changeForm, setChangeForm] = useState({ current: '', newPass: '', confirm: '' });
  const [forgotUsername, setForgotUsername] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [tempPassword, setTempPassword] = useState('');
  const [firstLoginUser, setFirstLoginUser] = useState(null);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const user = await login(form.username, form.password);
      if (user?.first_login) { setFirstLoginUser(user); setMode('change'); }
    } catch (err) {
      setError(err.message || 'Login failed');
    } finally { setLoading(false); }
  };

  const handleForgot = async (e) => {
    e.preventDefault();
    setError(''); setSuccess(''); setLoading(true);
    try {
      const res = await api.forgotPassword({ username: forgotUsername });
      if (res.temp_password) {
        setTempPassword(res.temp_password);
        setSuccess('Temporary password generated. Note it below and use it to login.');
      } else { setSuccess(res.message); }
    } catch (err) {
      setError(err.message || 'Failed to reset password');
    } finally { setLoading(false); }
  };

  const handleChangePassword = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    if (changeForm.newPass.length < 8) { setError('New password must be at least 8 characters'); setLoading(false); return; }
    if (changeForm.newPass !== changeForm.confirm) { setError('Passwords do not match'); setLoading(false); return; }
    try {
      await api.changePassword({ current_password: changeForm.current, new_password: changeForm.newPass });
      setSuccess('Password changed! Logging you in...');
      setTimeout(() => setMode('login'), 1500);
    } catch (err) {
      setError(err.message || 'Failed to change password');
    } finally { setLoading(false); }
  };

  const inputStyle = {
    width: '100%', padding: '10px 12px', fontSize: 14,
    border: '1px solid #ddd', borderRadius: 5,
    fontFamily: 'inherit', boxSizing: 'border-box', outline: 'none',
    background: '#f9f9f9', color: '#222',
  };
  const labelStyle = { fontSize: 11, color: '#888', display: 'block', marginBottom: 4, textTransform: 'uppercase', letterSpacing: '0.07em', fontWeight: 600 };
  const btnStyle = { width: '100%', padding: '11px', fontSize: 14, fontWeight: 700, border: 'none', borderRadius: 5, background: '#00AEEF', color: 'white', cursor: 'pointer', marginTop: 8 };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundImage: `url("${TRUCK_BG}")`,
      backgroundSize: 'cover',
      backgroundPosition: 'center top',
    }}>
      {/* White login card with logo inside at top */}
      <div style={{
        background: 'white',
        borderRadius: 10,
        padding: '28px 30px 24px',
        width: '100%',
        maxWidth: 380,
        margin: '20px 16px',
        boxShadow: '0 8px 40px rgba(0,0,0,0.22)',
      }}>

        {/* Logo inside card */}
        <div style={{ borderBottom: '1px solid #eee', paddingBottom: 16, marginBottom: 20 }}>
          <InterlandLogo />
        </div>

        {mode === 'login' && (
          <form onSubmit={handleLogin}>
            {error && <div style={{ color: '#e53e3e', fontSize: 13, marginBottom: 12, textAlign: 'center', background: '#fff5f5', padding: '8px 10px', borderRadius: 5, border: '1px solid #fed7d7' }}>{error}</div>}
            <div style={{ marginBottom: 12 }}>
              <label style={labelStyle}>Username</label>
              <input style={inputStyle} type="text" required autoFocus value={form.username}
                onChange={e => setForm(f => ({ ...f, username: e.target.value }))}
                placeholder="Enter your username" />
            </div>
            <div style={{ marginBottom: 18 }}>
              <label style={labelStyle}>Password</label>
              <input style={inputStyle} type="password" required value={form.password}
                onChange={e => setForm(f => ({ ...f, password: e.target.value }))}
                placeholder="Enter your password" />
            </div>
            <button type="submit" style={btnStyle} disabled={loading}>
              {loading ? 'Signing in...' : 'LOGIN'}
            </button>
            <div style={{ textAlign: 'center', marginTop: 14 }}>
              <button type="button"
                onClick={() => { setMode('forgot'); setError(''); setSuccess(''); }}
                style={{ background: 'none', border: 'none', color: '#00AEEF', cursor: 'pointer', fontSize: 13 }}>
                Forgot password?
              </button>
            </div>
          </form>
        )}

        {mode === 'forgot' && (
          <form onSubmit={handleForgot}>
            <p style={{ fontSize: 13, color: '#666', marginBottom: 14, textAlign: 'center' }}>Enter your username to get a temporary password.</p>
            {error && <div style={{ color: '#e53e3e', fontSize: 13, marginBottom: 10, textAlign: 'center' }}>{error}</div>}
            {success && <div style={{ background: '#f0fdf4', border: '1px solid #86efac', color: '#059669', padding: '8px 10px', borderRadius: 5, fontSize: 13, marginBottom: 10 }}>{success}</div>}
            {tempPassword && (
              <div style={{ background: '#fffbeb', border: '2px solid #00AEEF', borderRadius: 6, padding: 12, marginBottom: 12, textAlign: 'center' }}>
                <div style={{ fontSize: 10, color: '#666', marginBottom: 4, textTransform: 'uppercase', letterSpacing: '0.06em' }}>Temporary password</div>
                <div style={{ fontSize: 20, fontWeight: 700, fontFamily: 'monospace', color: '#003d7a', letterSpacing: '0.1em' }}>{tempPassword}</div>
                <div style={{ fontSize: 11, color: '#666', marginTop: 4 }}>Use this to login - you will be asked to change it</div>
              </div>
            )}
            <div style={{ marginBottom: 14 }}>
              <label style={labelStyle}>Username</label>
              <input style={inputStyle} type="text" required autoFocus value={forgotUsername}
                onChange={e => setForgotUsername(e.target.value)} placeholder="Enter your username" />
            </div>
            <button type="submit" style={btnStyle} disabled={loading}>{loading ? 'Generating...' : 'Get Temporary Password'}</button>
            <div style={{ textAlign: 'center', marginTop: 12 }}>
              <button type="button"
                onClick={() => { setMode('login'); setError(''); setSuccess(''); setTempPassword(''); }}
                style={{ background: 'none', border: 'none', color: '#00AEEF', cursor: 'pointer', fontSize: 13 }}>
                Back to login
              </button>
            </div>
          </form>
        )}

        {mode === 'change' && (
          <form onSubmit={handleChangePassword}>
            <div style={{ background: '#fffbeb', border: '1px solid #00AEEF', borderRadius: 5, padding: 10, marginBottom: 16, fontSize: 13, color: '#003d7a', textAlign: 'center' }}>
              Welcome{firstLoginUser?.name ? `, ${firstLoginUser.name}` : ''}! Please set a new password.
            </div>
            {error && <div style={{ color: '#e53e3e', fontSize: 13, marginBottom: 10, textAlign: 'center' }}>{error}</div>}
            {success && <div style={{ color: '#059669', fontSize: 13, marginBottom: 10, textAlign: 'center' }}>{success}</div>}
            <div style={{ marginBottom: 12 }}>
              <label style={labelStyle}>Current / Temporary Password</label>
              <input style={inputStyle} type="password" required autoFocus value={changeForm.current}
                onChange={e => setChangeForm(f => ({ ...f, current: e.target.value }))} placeholder="Enter current password" />
            </div>
            <div style={{ marginBottom: 12 }}>
              <label style={labelStyle}>New Password</label>
              <input style={inputStyle} type="password" required value={changeForm.newPass}
                onChange={e => setChangeForm(f => ({ ...f, newPass: e.target.value }))} placeholder="Minimum 8 characters" />
            </div>
            <div style={{ marginBottom: 18 }}>
              <label style={labelStyle}>Confirm New Password</label>
              <input style={inputStyle} type="password" required value={changeForm.confirm}
                onChange={e => setChangeForm(f => ({ ...f, confirm: e.target.value }))} placeholder="Repeat new password" />
            </div>
            <button type="submit" style={btnStyle} disabled={loading}>{loading ? 'Saving...' : 'Set New Password'}</button>
          </form>
        )}

        <div style={{ textAlign: 'center', marginTop: 18, fontSize: 11, color: '#bbb', borderTop: '1px solid #f0f0f0', paddingTop: 12 }}>
          INTERLAND DISTRIBUTION {new Date().getFullYear()} v1.0.0
        </div>
      </div>
    </div>
  );
}
